#!/usr/bin/env python3

def read_input_file():
    """Read the input file and parse the transaction data"""
    try:
        with open('src/INPUT.DAT', 'r') as f:
            data = f.read().strip()

        if len(data) < 22:  # 4+4+4+10 minimum
            print("Error: Input file is empty")
            return None

        buyer_id = data[0:4]
        seller_id = data[4:8]
        book_id = data[8:12]
        amount = int(data[12:22])

        return buyer_id, seller_id, book_id, amount
    except Exception as e:
        print("Error: Input file is empty")
        return None

def read_accounts():
    """Read accounts from ACCOUNTS.DAT file"""
    accounts = []
    try:
        with open('data/ACCOUNTS.DAT', 'r') as f:
            data = f.read()

        # Parse accounts: each record is 4+20+10=34 characters
        for i in range(0, len(data), 34):
            if i + 34 <= len(data):
                account_id = data[i:i+4]
                account_name = data[i+4:i+24]
                account_balance = int(data[i+24:i+34])
                accounts.append({
                    'id': account_id,
                    'name': account_name,
                    'balance': account_balance
                })
    except Exception:
        pass

    return accounts

def read_books():
    """Read books from BOOKS.DAT file"""
    books = []
    try:
        with open('data/BOOKS.DAT', 'r') as f:
            data = f.read()

        # Parse books: each record is 4+20+4=28 characters
